module RefModule (
    input [15:0] data_in, // 4 elements of 4 bits each
    output reg [15:0] data_out // sorted 4 elements of 4 bits each
);
    integer i, j;
    reg [3:0] final_sig [0:3]; // temporary storage for sorting

    always @* begin
        // Load input data into temporary array
        for (i = 0; i < 4; i = i + 1) begin
            final_sig[i] = data_in[i*4 +: 4];
        end

        // Bubble sort algorithm
        for (i = 0; i < 3; i = i + 1) begin
            for (j = 0; j < 3 - i; j = j + 1) begin
                if (final_sig[j] > final_sig[j + 1]) begin
                    // Swap
                    final_sig[j] = final_sig[j] ^ final_sig[j + 1];
                    final_sig[j + 1] = final_sig[j] ^ final_sig[j + 1];
                    final_sig[j] = final_sig[j] ^ final_sig[j + 1];
                end
            end
        end

        // Load sorted data into output
        data_out = {final_sig[3], final_sig[2], final_sig[1], final_sig[0]};
    end
endmodule
